    /**
     * @return array<string, mixed>
     */
    private static function def(
        string $slug,
        string $title,
        string $category,
        string $excerpt,
        string $metaTitle,
        string $metaDescription,
        string $metaKeywords,
    ): array {
        return [
            'slug' => $slug,
            'title' => $title,
            'category' => $category,
            'excerpt' => $excerpt,
            'meta_title' => $metaTitle,
            'meta_description' => $metaDescription,
            'meta_keywords' => $metaKeywords,
        ];
    }

    public static function build(array $definition): string
    {
        $html = self::bodyFor($definition['category'], $definition['slug']);

        return GurgaonBlogContentBuilder::enrichPublic($html, $definition['category'], [
            'title' => $definition['title'],
            'slug' => $definition['slug'],
        ]);
    }

    private static function bodyFor(string $category, string $slug): string
    {
        $focus = self::focusFor($category);

        return self::article($focus['keyword'], $focus['intro'], $focus['sections']);
    }

