    /**
     * @return list<array{heading: string, paragraphs: list<string>, list?: list<string>}>}
     */
    private static function sectionsFor(string $category): array
    {
        if (str_starts_with($category, 'commercial_')) {
            return self::commercialSections($category);
        }

        if (str_starts_with($category, 'buyer_')) {
            return self::buyerSections($category);
        }

        return self::lifestyleSections($category);
    }

