            [
                'heading' => 'Choosing the Right Neighbourhood',
                'paragraphs' => ['Match locality to life stage — young professionals prioritise commute; families prioritise schools and parks.', 'Ocean Realtors helps compare societies on ground reality, not brochure maps alone.'],
            ],
            [
                'heading' => 'Practical Living Checklist',
                'paragraphs' => ['Test peak-hour commute, grocery access, and power backup in summer before token.', 'Speak to residents about maintenance responsiveness and visitor policies.'],
                'list' => ['School and hospital proximity', 'Internal road safety and parking', 'Society maintenance quality', 'Retail and dining within 10 minutes'],
            ],
        ];
    }

    /**
     * @param  list<array{heading: string, paragraphs: list<string>, list?: list<string>}>  $sections
     */
    private static function article(string $keyword, string $intro, array $sections): string
    {
        $html = '<p>'.$intro.'</p>';
        $html .= '<p>This guide on <strong>'.$keyword.'</strong> helps buyers, tenants, investors, and business owners navigate Gurgaon\'s 2026 market with clarity. Ocean Realtors provides verified guidance — call or WhatsApp for personalised support.</p>';

        foreach ($sections as $section) {
            $html .= '<h2>'.htmlspecialchars($section['heading'], ENT_QUOTES, 'UTF-8').'</h2>';
            foreach ($section['paragraphs'] as $paragraph) {
                $html .= '<p>'.$paragraph.'</p>';
            }
            if (! empty($section['list'])) {
                $html .= '<ul>';
                foreach ($section['list'] as $item) {
                    $html .= '<li>'.$item.'</li>';
                }
                $html .= '</ul>';
            }
        }

        $html .= '<h2>How Ocean Realtors Helps</h2>';
        $html .= '<p>From '.$keyword.' to end-to-end transaction support, Ocean Realtors offers curated options, transparent pricing, and paperwork coordination. Contact our Gurgaon team today for a tailored shortlist.</p>';

        return $html;
    }
}
